using UnityEngine;

/// <summary>
/// "Bolha de Coral" (Tarefa #14): bolha de ar interactiva encontrada em zonas
/// de coral/recifes. Ao ser tocada por um player com WaterMotor2D activo, dá
/// um impulso vertical (ajuda a alcançar zonas altas debaixo de água ou a
/// voltar rapidamente à superfície) e entra em recarga (ou desactiva-se, se
/// "respawnTime" for 0 — uso único).
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class CoralBubble : MonoBehaviour
{
    [Header("Impulso")]
    [Tooltip("Velocidade vertical (m/s) aplicada ao player ao tocar a bolha.")]
    public float launchForce = 14f;

    [Tooltip("Tempo (s) até a bolha reaparecer depois de usada. 0 = uso único (fica desactivada).")]
    public float respawnTime = 4f;

    [Header("Visual / Som")]
    public SpriteRenderer visual;
    public ParticleSystem popVfx;
    public AudioClip popSfx;

    private Collider2D _col;
    private bool _available = true;

    private void Awake()
    {
        _col = GetComponent<Collider2D>();
    }

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!_available || !other.CompareTag("Player")) return;

        var waterMotor = other.GetComponent<WaterMotor2D>();
        if (waterMotor == null || !waterMotor.IsActive) return;

        var rb = other.GetComponent<Rigidbody2D>();
        if (rb != null)
            rb.linearVelocity = new Vector2(rb.linearVelocity.x, launchForce);

        if (popVfx != null) popVfx.Play();
        AudioManager.Instance?.PlaySE(popSfx);

        SetAvailable(false);

        if (respawnTime > 0f)
            Invoke(nameof(Respawn), respawnTime);
    }

    private void Respawn() => SetAvailable(true);

    private void SetAvailable(bool available)
    {
        _available = available;

        if (_col != null) _col.enabled = available;
        if (visual != null) visual.enabled = available;
    }

    private void OnDrawGizmosSelected()
    {
        Gizmos.color = new Color(0.6f, 0.95f, 1f, 0.6f);
        Gizmos.DrawWireSphere(transform.position, 0.4f);
        Gizmos.DrawLine(transform.position, transform.position + Vector3.up * 1f);
    }
}
